<script setup lang="ts">
import { ref, watch } from 'vue';

const PREF_KEYS: Record<string, string> = {
  girls: 'msp_v4:girls_view_mode',
  present: 'msp_v4:present_view_mode',
};

const props = withDefaults(
  defineProps<{
    itemCount?: number;
    threshold?: number;
    storageKey?: string;
  }>(),
  {
    threshold: 5,
    storageKey: 'girls',
  },
);

const emit = defineEmits<{
  change: [mode: string];
}>();

function getStored(): string {
  try {
    return localStorage.getItem(PREF_KEYS[props.storageKey] || PREF_KEYS.girls) || 'compact';
  } catch {
    return 'compact';
  }
}
function setStored(v: string) {
  try {
    localStorage.setItem(PREF_KEYS[props.storageKey] || PREF_KEYS.girls, v);
  } catch {
    /* noop */
  }
}

const shouldAutoCompact = (props.itemCount ?? 0) > props.threshold;
const mode = ref<string>(shouldAutoCompact ? 'compact' : getStored());

watch(mode, v => emit('change', v), { immediate: true });

function setMode(v: string) {
  mode.value = v;
  setStored(v);
}
</script>

<template>
  <div class="view-toggle">
    <button
      class="toggle-btn"
      :class="{ active: mode === 'compact' }"
      type="button"
      title="紧凑视图"
      aria-label="紧凑视图"
      @click="setMode('compact')"
    >
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <rect x="3" y="3" width="18" height="6" rx="1" fill="currentColor" />
        <rect x="3" y="11" width="18" height="6" rx="1" fill="currentColor" opacity="0.6" />
        <rect x="3" y="19" width="18" height="4" rx="1" fill="currentColor" opacity="0.3" />
      </svg>
    </button>
    <button
      class="toggle-btn"
      :class="{ active: mode === 'detail' }"
      type="button"
      title="详细视图"
      aria-label="详细视图"
      @click="setMode('detail')"
    >
      <svg viewBox="0 0 24 24" aria-hidden="true">
        <rect x="3" y="3" width="18" height="18" rx="2" fill="currentColor" opacity="0.2" />
        <rect x="5" y="5" width="14" height="4" rx="1" fill="currentColor" />
        <rect x="5" y="11" width="14" height="4" rx="1" fill="currentColor" opacity="0.7" />
        <rect x="5" y="17" width="8" height="2" rx="0.5" fill="currentColor" opacity="0.4" />
      </svg>
    </button>
  </div>
</template>

