  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.sigil__svg {
  overflow: visible;
}

/* ── Track ── */
.sigil__track {
  stroke: var(--c-mana-track-bg);
}

