.sigil__orbit {
  transform-origin: center;
  animation: orbit-rotate 20s linear infinite;
}
.sigil--fallen .sigil__orbit {
  animation-direction: reverse;
  animation-duration: 16s;
}

@keyframes orbit-rotate {
  to {
    transform: rotate(360deg);
  }
}

