}
.sigil__tick {
  stroke: currentColor;
  opacity: 0.18;
  transition: opacity 0.3s ease;
}

/* ── Center text ── */
.sigil__center-text--compact {
  font-size: 10px;
  font-weight: 800;
  fill: var(--c-ink-strong);
  font-family: var(--font-ui);
}

