  font-size: 28px;
  font-weight: 900;
  fill: var(--c-ink-strong);
  font-family: var(--font-ui);
  letter-spacing: 0.02em;
}

.sigil__center-max {
  font-size: 12px;
  font-weight: 600;
  fill: var(--c-ink-weak);
  font-family: var(--font-ui);
}

/* ── Stage-specific glow pulse ── */
.sigil--surge .sigil__arc {
  animation: surge-pulse 1.8s ease-in-out infinite;
}
.sigil--high .sigil__arc {
  animation: high-pulse 2.4s ease-in-out infinite;
}
.sigil--steady .sigil__arc {
  animation: steady-pulse 3s ease-in-out infinite;
}
.sigil--low .sigil__arc {
  animation: low-glimmer 2s ease-in-out infinite;
}
.sigil--empty .sigil__arc {
  animation: empty-flicker 0.9s ease-in-out infinite;
}

/* ── Fallen track tint ── */
.sigil--fallen.sigil--empty .sigil__track {
  stroke: rgba(208, 79, 130, 0.08);
}

@keyframes surge-pulse {
  0%,
  100% {
    opacity: 1;
  }
