  }
  40% {
    opacity: 0.25;
  }
  55% {
    opacity: 0.7;
  }
  70% {
    opacity: 0.15;
  }
  85% {
    opacity: 0.6;
  }
}

/* ── Compact overrides ── */
.sigil--compact .sigil__arc {
  animation: none;
}
.sigil--compact .sigil__center-text--compact {
  font-size: 10px;
}

/* Detail hover intensify */
.sigil:not(.sigil--compact):hover .sigil__aura {
