<script setup lang="ts">
import { computed, onMounted, ref, watchEffect } from 'vue';
import { expandProtectedNames, getMagicNameForState, resolveWorldbookKey } from '../magicNames';
import { useDataStore } from '../store';

const store = useDataStore();

// ── Worldbook-protected girl detection ──
// Same logic as MagicalGirlListPage.vue: a girl is "protected"
// if the worldbook has BOTH [角色] 真名-魔法少女 AND [角色] 真名-堕落魔法少女 entries.
const worldbookProtectedNames = ref<Set<string>>(new Set());

onMounted(async () => {
  try {
    const wbNames = getCharWorldbookNames('current');
    const primaryName = wbNames?.primary;
    if (!primaryName) return;
    const entries = await getWorldbook(primaryName);
    if (!Array.isArray(entries)) return;

    const byTrueName = new Map<string, { 常态: boolean; 堕落: boolean }>();
    for (const entry of entries) {
      const name = typeof entry?.name === 'string' ? entry.name : '';
      const match = name.match(/^\[角色\]\s+(.+?)-(魔法少女|堕落魔法少女)$/);
      if (!match) continue;
      const trueName = match[1].trim();
      const type = match[2];
      const existing = byTrueName.get(trueName) ?? { 常态: false, 堕落: false };
      if (type === '魔法少女') existing.常态 = true;
      else existing.堕落 = true;
      byTrueName.set(trueName, existing);
    }

    const protectedSet = new Set<string>();
    byTrueName.forEach((pair, trueName) => {
      if (pair.常态 && pair.堕落) protectedSet.add(trueName);
    });
    // 扩展别名：如"小银"→也加入"西娅"，"乌特迦·洛奇"→也加入"乌特迦"等
    worldbookProtectedNames.value = expandProtectedNames(protectedSet);
  } catch {
    /* gracefully ignore if worldbook API is unavailable */
  }
});

interface FallRequest {
  key: string;
  magicName: string;
  trueName: string;
  displayName: string;
  protected: boolean;
  typeLabel: string;
}

const selectedKey = ref('');
const newMagicName = ref('');
const confirmProtectedKey = ref('');

function isProtected(key: string, girl: Record<string, unknown>): boolean {
  const trueName = (girl.真名 as string)?.trim();
  const aliasToCheck = trueName && trueName !== '???' ? trueName : key.trim();
  // 通过 resolveWorldbookKey 将别名反查回世界书真名后再检查
  const wbKey = resolveWorldbookKey(aliasToCheck);
  return worldbookProtectedNames.value.has(aliasToCheck) || worldbookProtectedNames.value.has(wbKey);
}

const items = computed<FallRequest[]>(() => {
  const girls = ((store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>) ?? {};
  return Object.entries(girls)
    .filter(([, g]) => g.精神极限 === true)
    .sort(([a], [b]) => a.localeCompare(b, 'zh-Hans-CN'))
    .map(([key, g]) => {
      const 暴露 = g.暴露 === true;
      const rawTrueName = (g.真名 as string) || '???';
      return {
        key,
        magicName: (g.魔法名 as string) || '???',
        trueName: rawTrueName,
        displayName: 暴露 ? rawTrueName : '???',
        protected: isProtected(key, g),
        typeLabel: g.是否堕落 ? '堕落魔法少女' : '魔法少女',
      };
    });
});

function reset() {
  selectedKey.value = '';
  newMagicName.value = '';
  confirmProtectedKey.value = '';
}

watchEffect(() => {
  if (selectedKey.value && !items.value.some(i => i.key === selectedKey.value)) {
    reset();
  }
});

function confirmProtectedFall(key: string) {
  const girl = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  if (!girl[key]) return;

  const item = items.value.find(i => i.key === key);
  if (!item) return;

  const isFallen = girl[key].是否堕落 === true;
  // 自动从映射表获取反转后的魔法名
  const targetFallen = !isFallen; // 堕落→常态, 常态→堕落
  const autoName = getMagicNameForState(item.trueName, targetFallen);

  girl[key].是否堕落 = targetFallen;
  if (autoName) girl[key].魔法名 = autoName;
  girl[key].精神极限 = false;
  if (confirmProtectedKey.value === key) reset();
}

function cancelFall(key: string) {
  const girl = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  if (!girl[key]) return;

  girl[key].精神极限 = false;
  if (selectedKey.value === key) reset();
}

function saveDynamicFall(key: string) {
  const girl = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  if (!girl[key] || !newMagicName.value.trim()) return;

  // 动态角色: 常态→堕落 或 堕落→常态，都需要填写新魔法名
  const wasFallen = girl[key].是否堕落 === true;
  girl[key].是否堕落 = !wasFallen;
  girl[key].魔法名 = newMagicName.value.trim();
  girl[key].精神极限 = false;
  reset();
}

function selectForFall(key: string) {
  const girl = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  if (!girl[key]) return;

  const item = items.value.find(i => i.key === key);
  if (!item || item.protected) {
    // 世界书内置角色: 展示确认界面（含自动魔法名预览）
    confirmProtectedKey.value = key;
    const isFallen = girl[key].是否堕落 === true;
    const targetFallen = !isFallen;
    const autoName = getMagicNameForState(item?.trueName || (girl[key].真名 as string) || key, targetFallen);
    newMagicName.value = autoName || (girl[key].魔法名 as string) || '???';
    return;
  }

  selectedKey.value = key;
  newMagicName.value = (girl[key].魔法名 as string) || '';
}
</script>

<template>
  <section v-if="items.length" class="panel">
    <div class="head">
      <div>
        <div class="title">精神极限警示</div>
        <div class="subtitle">到达精神极限后，是否反转只由玩家决定</div>
      </div>
      <div class="count">待处理 {{ items.length }}</div>
    </div>
    <div class="list">
      <article v-for="item in items" :key="item.key" class="item">
        <div class="top-row">
          <div class="identity">
            <div class="name">{{ item.magicName }}</div>
            <div class="sub">真名：{{ item.displayName }}</div>
          </div>
          <div class="badge-group">
            <div class="badge type">{{ item.typeLabel }}</div>
            <div class="badge">精神已达极限</div>
          </div>
        </div>
        <div class="reason">{{ item.magicName }} 的精神已达极限，真的要让她反转吗？</div>

        <!-- 世界书内置角色确认流程 -->
        <template v-if="confirmProtectedKey === item.key">
          <div class="protected-confirm">
            <div class="protected-preview">
              <span class="preview-label">反转后魔法名：</span>
              <span class="preview-name">{{ newMagicName }}</span>
            </div>
            <div class="hint">世界书内置角色反转后魔法名将自动设置，无需手动输入。</div>
            <div class="actions">
              <button class="btn danger" type="button" @click="confirmProtectedFall(item.key)">是，确认反转</button>
              <button
                class="btn"
                type="button"
                @click="
                  confirmProtectedKey = '';
                  newMagicName = '';
                "
              >
                取消
              </button>
            </div>
          </div>
        </template>
        <!-- 动态角色填写魔法名流程 -->
        <template v-else-if="selectedKey === item.key && !item.protected">
          <label class="field">
            <span class="field-label">新的魔法名</span>
            <input v-model="newMagicName" class="input" type="text" placeholder="输入切换后的魔法名" />
          </label>
          <div class="hint">动态角色没有世界书纠错，所以确认反转时需要同时填写新的魔法名。</div>
          <div class="actions">
            <button
              class="btn danger"
              type="button"
              :disabled="!newMagicName.trim()"
              @click="saveDynamicFall(item.key)"
            >
              保存并反转
            </button>
            <button class="btn" type="button" @click="reset">取消</button>
          </div>
        </template>
        <!-- 默认操作按钮 -->
        <template v-else>
          <div class="actions">
            <button class="btn danger" type="button" @click="selectForFall(item.key)">
              {{ item.protected ? '是，确认反转' : '填写魔法名并反转' }}
            </button>
            <button class="btn" type="button" @click="cancelFall(item.key)">否，保持现状</button>
          </div>
        </template>
      </article>
    </div>
  </section>
</template>

