<script setup lang="ts">
import { computed, provide, ref } from 'vue';
import FallRequestPanel from './components/FallRequestPanel.vue';
import type { Tab } from './components/TabNav.vue';
import TabNav from './components/TabNav.vue';
import ThemeToggle from './components/ThemeToggle.vue';
import MagicalGirlListPage from './pages/MagicalGirlListPage.vue';
import PresentCharactersPage from './pages/PresentCharactersPage.vue';
import RavenPage from './pages/RavenPage.vue';
import { useDataStore } from './store';

const store = useDataStore();

const TABS: Tab[] = [
  { id: 'present', label: '在场角色' },
  { id: 'girls', label: '魔法少女' },
  { id: 'raven', label: '渡鸦' },
];

const PREF_KEY = 'msp_v4:status_bar:tab';
function getStoredTab(): string {
  try {
    const v = localStorage.getItem(PREF_KEY);
    return v && TABS.some(t => t.id === v) ? v : 'present';
  } catch {
    return 'present';
  }
}
function setStoredTab(v: string) {
  try {
    localStorage.setItem(PREF_KEY, v);
  } catch {
    /* noop */
  }
}

const activeTab = ref(getStoredTab());
const selectGirlRef = ref<string | null>(null);

function switchToTab(tab: string, opts?: { selectGirl: string }) {
  activeTab.value = tab;
  setStoredTab(tab);
  if (opts?.selectGirl) {
    selectGirlRef.value = opts.selectGirl;
    setTimeout(() => {
      selectGirlRef.value = null;
    }, 100);
  }
}

provide('switchToTab', switchToTab);
provide('selectGirlEvent', selectGirlRef);

const locationText = computed(() => {
  const loc = store.data.地点;
  return [loc?.城市?.trim() || '新都', loc?.地区?.trim() || '未知地区', loc?.地址?.trim() || '未知地点']
    .filter(Boolean)
    .join(' · ');
});
</script>

<template>
  <div class="shell">
    <!-- Header -->
    <header class="top">
      <div class="header-row">
        <div class="location-card">
          <div class="location-head">
            <div class="eyebrow">当前地点</div>
          </div>
          <div class="location-inline">{{ locationText }}</div>
        </div>
        <ThemeToggle />
      </div>
    </header>

    <!-- Fall Request Panel -->
    <FallRequestPanel />

    <!-- Tab Navigation -->
    <TabNav :tabs="TABS" v-model="activeTab" />

    <!-- Content -->
    <main class="content">
      <PresentCharactersPage v-if="activeTab === 'present'" key="present" />
      <MagicalGirlListPage v-else-if="activeTab === 'girls'" key="girls" />
      <RavenPage v-else-if="activeTab === 'raven'" key="raven" />
    </main>
  </div>
</template>

