<script setup lang="ts">
import { computed, reactive, ref, watchEffect } from 'vue';
import { useDataStore } from '../store';

const store = useDataStore();

// ── Helpers ──
// ── State ──
const skillDialogOpen = ref(false);
const selectedSkill = ref('');
const skillExpanded = ref(false);

const skillForm = reactive({ sourceName: '', name: '', desc: '' });

// ── Computed ──
const skills = computed(() => {
  const all = (store.data.渡鸦.技能 as Record<string, { 说明: string }>) ?? {};
  return Object.entries(all)
    .map(([name, s]) => ({ name, desc: s?.说明 ?? '' }))
    .sort((a, b) => a.name.localeCompare(b.name, 'zh-Hans-CN'));
});

const currentSkill = computed(() => skills.value.find(s => s.name === selectedSkill.value) ?? null);
const isLong = computed(() => (currentSkill.value?.desc?.length ?? 0) > 90);

const formHasName = computed(() => skillForm.sourceName || skillForm.name.trim());

// ── Actions ──
function selectSkill(name: string) {
  selectedSkill.value = name;
}

function openSkillDialog() {
  if (currentSkill.value) loadSkillForm(currentSkill.value.name);
  else resetForm();
  skillDialogOpen.value = true;
}

function closeSkillDialog() {
  skillDialogOpen.value = false;
}

function resetForm() {
  skillForm.sourceName = '';
  skillForm.name = '';
  skillForm.desc = '';
}

function loadSkillForm(name: string) {
  const s = (store.data.渡鸦.技能 as Record<string, { 说明: string }>)?.[name];
  skillForm.sourceName = name;
  skillForm.name = name;
  skillForm.desc = s?.说明 ?? '';
}

function saveSkill() {
  const name = skillForm.name.trim();
  if (!name) return;

  const all = (store.data.渡鸦.技能 as Record<string, { 说明: string }>) ?? {};
  if (skillForm.sourceName && skillForm.sourceName !== name && skillForm.sourceName in all) {
    delete all[skillForm.sourceName];
  }
  all[name] = { 说明: skillForm.desc.trim() };
  skillForm.sourceName = name;
  skillForm.name = name;
  selectedSkill.value = name;
}

function deleteSkill() {
  const name = formHasName.value.trim();
  if (!name) return;

  const all = (store.data.渡鸦.技能 as Record<string, { 说明: string }>) ?? {};
  if (name in all) {
    delete all[name];
    if (selectedSkill.value === name) selectedSkill.value = '';
  }
  resetForm();
}

// Auto-select first skill
watchEffect(() => {
  if (!skills.value.length) {
    selectedSkill.value = '';
    skillExpanded.value = false;
    return;
  }
  if (selectedSkill.value && skills.value.some(s => s.name === selectedSkill.value)) return;
  selectedSkill.value = skills.value[0].name;
});

watchEffect(() => {
  skillExpanded.value = false;
});
</script>

<template>
  <section class="section">
    <!-- Wing button -->
    <div class="section-head">
      <button class="wing-button" type="button" title="技能管理" aria-label="技能管理" @click="openSkillDialog">
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path
            d="M5.2 19.2c.7-3.7 2.7-6.7 6-9 1-.7 2.2-1.3 3.8-2 .6-.3.9-.9.8-1.5-.2-1-.8-2-1.9-3.1 3.5.7 5.8 2.9 5.8 6.2 0 1.8-.7 3.4-1.9 4.8-.4.5-1.1.6-1.7.3l-1.6-.9c-1.2 2.1-3.1 3.7-5.7 4.8-1.5.7-3 1-5.6.4z"
            fill="currentColor"
          />
          <path
            d="M8.7 16.7c.3-2 1.5-3.7 3.6-5.2-2.9.8-5 2.6-6.3 5.3 1.2.2 1.9.2 2.7-.1z"
            fill="rgba(255,255,255,0.25)"
          />
        </svg>
      </button>
    </div>

    <!-- Skills Panel -->
    <div class="panel">
      <div class="panel-head">
        <div>
          <div class="panel-title">已掌握技能</div>
          <div class="panel-caption">点击技能查看详情</div>
        </div>
        <div class="panel-count">{{ skills.length }} 项</div>
      </div>

      <!-- Skill chips -->
      <div v-if="skills.length" class="skill-list">
        <button
          v-for="s in skills"
          :key="s.name"
          class="skill-item"
          :class="{ active: s.name === selectedSkill }"
          type="button"
          @click="selectSkill(s.name)"
        >
          <span class="skill-name">{{ s.name }}</span>
        </button>
      </div>
      <div v-else class="empty">暂无技能</div>

      <!-- Skill detail -->
      <div v-if="currentSkill" class="skill-detail">
        <div class="skill-detail-head">
          <div>
            <div class="skill-detail-title">{{ currentSkill.name }}</div>
          </div>
          <button v-if="isLong" class="detail-toggle" type="button" @click="skillExpanded = !skillExpanded">
            {{ skillExpanded ? '收起' : '展开' }}
          </button>
        </div>
        <div class="skill-detail-text" :class="{ collapsed: isLong && !skillExpanded }">
          {{ currentSkill.desc || '暂无技能说明。' }}
        </div>
      </div>
      <div v-else class="detail-empty">未选择技能</div>
    </div>

    <!-- 🆕 Skill management dialog -->
    <Transition name="fade">
      <div v-if="skillDialogOpen" class="dialog-mask" @click.self="closeSkillDialog">
        <div class="dialog">
          <div class="dialog-head">
            <div class="dialog-title">渡鸦技能管理</div>
            <div class="dialog-tools">
              <button class="btn ghost" type="button" @click="resetForm">新增技能</button>
              <button class="dialog-close" type="button" aria-label="关闭" @click="closeSkillDialog">&times;</button>
            </div>
          </div>
          <div class="dialog-grid">
            <div class="manager-list">
              <button
                v-for="s in skills"
                :key="s.name"
                class="manager-item"
                type="button"
                @click="loadSkillForm(s.name)"
              >
                <div class="manager-name">{{ s.name }}</div>
                <div class="manager-desc">{{ s.desc || '暂无说明' }}</div>
              </button>
              <div v-if="!skills.length" class="manager-empty">还没有技能，先新增一条。</div>
            </div>
            <div class="editor-panel">
              <div class="row">
                <div class="label">技能名</div>
                <div class="value">
                  <input v-model="skillForm.name" class="input" type="text" placeholder="例如：幻胧" />
                </div>
              </div>
              <div class="row">
                <div class="label">说明</div>
                <div class="value">
                  <textarea v-model="skillForm.desc" class="textarea" rows="5" placeholder="输入技能效果说明" />
                </div>
              </div>
              <div class="actions">
                <button class="btn primary" type="button" :disabled="!skillForm.name.trim()" @click="saveSkill">
                  保存
                </button>
                <button class="btn danger" type="button" :disabled="!formHasName" @click="deleteSkill">删除</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </Transition>
  </section>
</template>

