<script setup lang="ts">
import { computed, inject, onMounted, ref, watchEffect } from 'vue';
import ManaSigil from '../components/ManaSigil.vue';
import ViewModeToggle from '../components/ViewModeToggle.vue';
import { expandProtectedNames, getMagicNameForState } from '../magicNames';
import { useDataStore } from '../store';

const store = useDataStore();

// ── helpers ──
const SURGE = 85;
const HIGH = 60;
const STEADY = 35;
const LOW = 15;
function manaStage(v: number) {
  if (v >= SURGE) return 'surge';
  if (v >= HIGH) return 'high';
  if (v >= STEADY) return 'steady';
  if (v >= LOW) return 'low';
  return 'empty';
}
function manaLabel(s: string) {
  const m: Record<string, string> = { surge: '充盈', high: '高涨', steady: '稳定', low: '低鸣', empty: '枯竭' };
  return m[s] || '枯竭';
}
function attitudeTone(a: string) {
  const m: Record<string, string> = {
    陌生: 'stranger',
    无关心: 'detached',
    一般: 'neutral',
    信任: 'trust',
    恋心: 'love',
    讨厌: 'dislike',
    死仇: 'hostile',
    爱恨交织: 'conflicted',
  };
  return m[a] || 'neutral';
}

function isKnown(v: unknown): v is string {
  return typeof v === 'string' && v.trim().length > 0 && v.trim() !== '???';
}
function matchesAlias(name: string, girl: Record<string, unknown>): boolean {
  const n = name.trim();
  return n === girl.真名 || n === girl.魔法名;
}

const INITIAL_FALLEN = new Set(['芦屋道满', '莫里娅蒂娜', '乌特迦·洛奇']);

// ── Worldbook-protected girl detection ──
// Mirrors the logic from 世界书状态联动v1.2.js:
// A girl is "protected" if the worldbook has BOTH [角色] 真名-魔法少女 AND [角色] 真名-堕落魔法少女 entries.
const worldbookProtectedNames = ref<Set<string>>(new Set());

onMounted(async () => {
  try {
    const wbNames = getCharWorldbookNames('current');
    const primaryName = wbNames?.primary;
    if (!primaryName) return;
    const entries = await getWorldbook(primaryName);
    if (!Array.isArray(entries)) return;

    // Build the same pairing index as the sync script
    const byTrueName = new Map<string, { 常态: boolean; 堕落: boolean }>();
    for (const entry of entries) {
      const name = typeof entry?.name === 'string' ? entry.name : '';
      const match = name.match(/^\[角色\]\s+(.+?)-(魔法少女|堕落魔法少女)$/);
      if (!match) continue;
      const trueName = match[1].trim();
      const type = match[2];
      const existing = byTrueName.get(trueName) ?? { 常态: false, 堕落: false };
      if (type === '魔法少女') existing.常态 = true;
      else existing.堕落 = true;
      byTrueName.set(trueName, existing);
    }

    const protectedSet = new Set<string>();
    byTrueName.forEach((pair, trueName) => {
      if (pair.常态 && pair.堕落) protectedSet.add(trueName);
    });
    // 扩展别名：如"小银"→也加入"西娅"，"乌特迦·洛奇"→也加入"乌特迦"等
    worldbookProtectedNames.value = expandProtectedNames(protectedSet);
  } catch {
    /* gracefully ignore if worldbook API is unavailable */
  }
});

// ── state ──
const selectedKey = ref('');
const viewMode = ref('compact');
const fallDialogOpen = ref(false);
const fallTargetKey = ref('');
const fallNewMagicName = ref('');
const fallToFallen = ref(false);
const deleteDialogOpen = ref(false);
const deleteTargetKey = ref('');

// 🆕 Knot CRUD dialog
const knotDialogOpen = ref(false);
const knotDialogMode = ref<'add' | 'edit'>('add');
const knotTargetGirlKey = ref('');
const knotOldName = ref('');
const knotName = ref('');
const knotDesc = ref('');

const injectSwitchToTab = inject<(tab: string, opts?: { selectGirl: string }) => void>('switchToTab', () => {});
const injectSelectGirl = inject<Ref<string | null>>('selectGirlEvent', ref(null));

watchEffect(() => {
  const name = injectSelectGirl?.value;
  if (name) selectedKey.value = name;
});

// ── computed ──
interface GirlItem {
  key: string;
  magicName: string;
  trueName: string;
  displayName: string;
  fallen: boolean;
  mentalBreak: boolean;
  protected: boolean;
  typeLabel: string;
  toneClass: string;
  magicCurrent: number;
  magicMax: number;
  magicPercent: number;
  manaStageClass: ReturnType<typeof manaStage>;
  manaStateLabel: string;
  attitude: string;
  attitudeToneClass: string;
  hasUnresolvedKnots: boolean;
  unresolvedKnots: { name: string; desc: string }[];
  resolvedKnots: { name: string; desc: string }[];
}

const girlsList = computed<GirlItem[]>(() => {
  const girls = ((store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>) ?? {};

  return Object.entries(girls)
    .map(([key, g]) => {
      const magicMax = Number(g.魔力上限) || 100;
      const magicCurrent = Number(g.魔力) || 0;
      const magicPercent = magicMax ? Math.round((magicCurrent / magicMax) * 100) : 0;
      const fallen = g.是否堕落 === true;
      const toneClass = fallen ? 'fallen' : 'normal';
      const stageClass = manaStage(magicPercent);

      const knots = (g.心结 as Record<string, { 描述: string; 是否解开: boolean }>) ?? {};
      const unresolvedKnots = Object.entries(knots)
        .filter(([, v]) => !v.是否解开)
        .map(([name, v]) => ({ name, desc: v.描述 || '???' }));
      const resolvedKnots = Object.entries(knots)
        .filter(([, v]) => v.是否解开)
        .map(([name, v]) => ({ name, desc: v.描述 || '' }));

      const 暴露 = g.暴露 === true;
      const rawTrueName = (g.真名 as string) || '???';
      const displayName = 暴露 ? rawTrueName : '???';

      return {
        key,
        magicName: (g.魔法名 as string) || '???',
        trueName: rawTrueName,
        displayName,
        fallen,
        mentalBreak: g.精神极限 === true,
        protected: worldbookProtectedNames.value.has((g.真名 as string)?.trim() || key.trim()),
        typeLabel: fallen ? '堕落魔法少女' : '魔法少女',
        toneClass,
        magicCurrent,
        magicMax,
        magicPercent,
        manaStageClass: stageClass,
        manaStateLabel: manaLabel(stageClass),
        attitude: (g.对主角的态度 as string) || '陌生',
        attitudeToneClass: attitudeTone((g.对主角的态度 as string) || '陌生'),
        hasUnresolvedKnots: unresolvedKnots.length > 0,
        unresolvedKnots,
        resolvedKnots,
      };
    })
    .sort((a, b) => a.magicName.localeCompare(b.magicName, 'zh-Hans-CN'));
});

const selectedGirl = computed(() => girlsList.value.find(g => g.key === selectedKey.value) ?? null);
const fallTargetGirl = computed(() => girlsList.value.find(g => g.key === fallTargetKey.value) ?? null);
const deleteTargetGirl = computed(() => girlsList.value.find(g => g.key === deleteTargetKey.value) ?? null);

// ── actions ──
function select(key: string) {
  selectedKey.value = key;
}
function back() {
  selectedKey.value = '';
}

function openFallDialog(key: string) {
  const g = girlsList.value.find(x => x.key === key);
  if (!g) return;
  fallTargetKey.value = key;
  fallToFallen.value = !g.fallen;

  // 世界书内置角色：自动从映射表获取反转后的魔法名
  if (g.protected) {
    const targetState = fallToFallen.value;
    const autoName = getMagicNameForState(g.trueName, targetState);
    fallNewMagicName.value = autoName || g.magicName;
  } else {
    fallNewMagicName.value = g.magicName;
  }
  fallDialogOpen.value = true;
}

function confirmFall() {
  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const key = fallTargetKey.value;
  if (!key || !fallNewMagicName.value.trim() || !girls[key]) return;
  girls[key].是否堕落 = fallToFallen.value;
  girls[key].魔法名 = fallNewMagicName.value.trim();
  girls[key].精神极限 = false;
  closeFallDialog();
}

function closeFallDialog() {
  fallDialogOpen.value = false;
  fallTargetKey.value = '';
  fallNewMagicName.value = '';
}

function openDeleteDialog(key: string) {
  deleteTargetKey.value = key;
  deleteDialogOpen.value = true;
}
function confirmDelete() {
  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const key = deleteTargetKey.value;
  if (key && girls[key]) {
    delete girls[key];
    if (selectedKey.value === key) back();
  }
  closeDeleteDialog();
}
function closeDeleteDialog() {
  deleteDialogOpen.value = false;
  deleteTargetKey.value = '';
}

// 🆕 Knot CRUD
function openAddKnot(girlKey: string) {
  knotDialogMode.value = 'add';
  knotTargetGirlKey.value = girlKey;
  knotOldName.value = '';
  knotName.value = '';
  knotDesc.value = '';
  knotDialogOpen.value = true;
}

function openEditKnot(girlKey: string, name: string, desc: string) {
  knotDialogMode.value = 'edit';
  knotTargetGirlKey.value = girlKey;
  knotOldName.value = name;
  knotName.value = name;
  knotDesc.value = desc;
  knotDialogOpen.value = true;
}

function confirmKnot() {
  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const girl = girls[knotTargetGirlKey.value];
  if (!girl || !knotName.value.trim()) return;

  const knots = (girl.心结 as Record<string, { 描述: string; 是否解开: boolean }>) ?? {};
  if (knotDialogMode.value === 'edit' && knotOldName.value && knotOldName.value !== knotName.value.trim()) {
    delete knots[knotOldName.value];
  }
  knots[knotName.value.trim()] = { 描述: knotDesc.value.trim() || '???', 是否解开: false };
  closeKnotDialog();
}

function closeKnotDialog() {
  knotDialogOpen.value = false;
  knotTargetGirlKey.value = '';
  knotOldName.value = '';
  knotName.value = '';
  knotDesc.value = '';
}

function toggleKnotResolved(girlKey: string, knotName: string, resolved: boolean) {
  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const girl = girls[girlKey];
  if (!girl) return;
  const knots = (girl.心结 as Record<string, { 描述: string; 是否解开: boolean }>) ?? {};
  if (knots[knotName]) {
    knots[knotName].是否解开 = resolved;
    // 保留描述不清空，重新激活时描述不丢失
  }
}

function deleteKnot(girlKey: string, knotName: string) {
  const girls = (store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>;
  const girl = girls[girlKey];
  if (!girl) return;
  const knots = (girl.心结 as Record<string, { 描述: string; 是否解开: boolean }>) ?? {};
  delete knots[knotName];
}
</script>

<template>
  <section class="section">
    <Transition name="page-swap" mode="out-in">
      <!-- ===== DETAIL VIEW ===== -->
      <div v-if="selectedGirl" key="detail" class="detail-view">
        <div class="detail-toolbar">
          <button class="back-button" type="button" @click="back">返回列表</button>
        </div>

        <article class="detail-card" :class="selectedGirl.toneClass">
          <!-- Hero -->
          <div class="hero-panel">
            <div class="identity-block">
              <div class="eyebrow">魔法名</div>
              <div class="hero-name">{{ selectedGirl.magicName }}</div>
              <div class="true-name-line">
                真名 <strong>{{ selectedGirl.displayName }}</strong>
              </div>
            </div>
            <div class="hero-badges">
              <span class="type-badge" :class="selectedGirl.toneClass">{{ selectedGirl.typeLabel }}</span>
              <span v-if="selectedGirl.mentalBreak" class="status-badge mental">精神极限</span>
            </div>
          </div>

          <!-- Status Row: attitude + mana -->
          <div class="status-row" :class="selectedGirl.toneClass">
            <span class="attitude-badge detail" :class="selectedGirl.attitudeToneClass">{{
              selectedGirl.attitude
            }}</span>
            <div class="status-mana">
              <ManaSigil
                :percent="selectedGirl.magicPercent"
                :current="selectedGirl.magicCurrent"
                :max="selectedGirl.magicMax"
                :stage="selectedGirl.manaStageClass"
                :fallen="selectedGirl.fallen"
              />
              <div class="mana-sigil-meta">
                <span class="mana-stage-label">{{ selectedGirl.manaStateLabel }}</span>
                <span class="mana-pct">{{ selectedGirl.magicPercent }}%</span>
              </div>
            </div>
          </div>

          <!-- 🆕 Knots -->
          <div class="knot-grid">
            <!-- Unresolved -->
            <section class="knot-panel unresolved">
              <div class="knot-head">
                <div class="knot-title">未解决心结</div>
                <div class="knot-count">{{ selectedGirl.unresolvedKnots.length }} 项</div>
              </div>
              <div v-if="selectedGirl.unresolvedKnots.length" class="knot-list">
                <article v-for="k in selectedGirl.unresolvedKnots" :key="`pending-${k.name}`" class="knot-item">
                  <div class="knot-item-head">
                    <div class="knot-name">{{ k.name }}</div>
                    <span class="knot-status unresolved">未解开</span>
                  </div>
                  <div class="knot-copy">{{ k.desc }}</div>
                  <div class="knot-item-actions">
                    <button
                      class="knot-btn knot-btn-resolve"
                      type="button"
                      @click="toggleKnotResolved(selectedGirl.key, k.name, true)"
                    >
                      ✓ 标记已解
                    </button>
                    <button
                      class="knot-btn knot-btn-edit"
                      type="button"
                      @click="openEditKnot(selectedGirl.key, k.name, k.desc)"
                    >
                      ✏ 编辑
                    </button>
                    <button
                      class="knot-btn knot-btn-delete"
                      type="button"
                      @click="deleteKnot(selectedGirl.key, k.name)"
                    >
                      ✕ 删除
                    </button>
                  </div>
                </article>
              </div>
              <div v-else class="knot-empty">当前没有待处理的心结。</div>
              <button class="knot-add-btn" type="button" @click="openAddKnot(selectedGirl.key)">+ 新增心结</button>
            </section>

            <!-- Resolved -->
            <section class="knot-panel resolved">
              <div class="knot-head">
                <div class="knot-title">已解决心结</div>
                <div class="knot-count">{{ selectedGirl.resolvedKnots.length }} 项</div>
              </div>
              <div v-if="selectedGirl.resolvedKnots.length" class="knot-list">
                <article v-for="k in selectedGirl.resolvedKnots" :key="`resolved-${k.name}`" class="knot-item">
                  <div class="knot-item-head">
                    <div class="knot-name">{{ k.name }}</div>
                    <span class="knot-status resolved">已解开</span>
                  </div>
                  <div class="knot-copy resolved-desc">{{ k.desc || '该心结已解开。' }}</div>
                  <div class="knot-item-actions">
                    <button
                      class="knot-btn knot-btn-reopen"
                      type="button"
                      @click="toggleKnotResolved(selectedGirl.key, k.name, false)"
                    >
                      ↻ 重新激活
                    </button>
                    <button
                      class="knot-btn knot-btn-delete"
                      type="button"
                      @click="deleteKnot(selectedGirl.key, k.name)"
                    >
                      ✕ 删除
                    </button>
                  </div>
                </article>
              </div>
              <div v-else class="knot-empty">还没有已解决的心结记录。</div>
            </section>
          </div>

          <!-- Fall/Delete actions -->
          <div class="detail-actions">
            <button v-if="selectedGirl.mentalBreak" class="btn" type="button" @click="openFallDialog(selectedGirl.key)">
              {{ selectedGirl.fallen ? '切换为常态' : '切换为堕落' }}
            </button>
            <button
              v-if="!selectedGirl.protected"
              class="btn danger"
              type="button"
              @click="openDeleteDialog(selectedGirl.key)"
            >
              删除记录
            </button>
          </div>
        </article>
      </div>

      <!-- ===== LIST VIEW ===== -->
      <div v-else key="list" class="list-view">
        <!-- Toolbar -->
        <div v-if="girlsList.length" class="toolbar">
          <div class="count">{{ girlsList.length }} 名魔法少女</div>
          <ViewModeToggle :item-count="girlsList.length" storage-key="girls" @change="v => (viewMode = v)" />
        </div>

        <!-- Compact -->
        <div v-if="girlsList.length && viewMode === 'compact'" class="compact-list">
          <button
            v-for="g in girlsList"
            :key="g.key"
            class="compact-girl"
            :class="[g.toneClass]"
            type="button"
            @click="select(g.key)"
          >
            <div class="compact-girl-main">
              <div class="compact-girl-name">{{ g.magicName }}</div>
              <span class="type-badge mini" :class="g.toneClass">{{ g.typeLabel }}</span>
              <span v-if="g.hasUnresolvedKnots" class="knot-dot" title="存在未解决心结" />
            </div>
            <div class="compact-girl-meta">
              <span class="attitude-badge compact" :class="g.attitudeToneClass">{{ g.attitude }}</span>
              <ManaSigil
                compact
                :percent="g.magicPercent"
                :current="g.magicCurrent"
                :max="g.magicMax"
                :stage="g.manaStageClass"
                :fallen="g.fallen"
              />
            </div>
          </button>
        </div>

        <!-- Detail cards -->
        <div v-else-if="girlsList.length && viewMode === 'detail'" class="list">
          <button
            v-for="g in girlsList"
            :key="g.key"
            class="girl-card"
            :class="[g.toneClass]"
            type="button"
            @click="select(g.key)"
          >
            <div class="card-head">
              <div class="card-identity">
                <div class="card-name">
                  {{ g.magicName }}
                  <span v-if="g.hasUnresolvedKnots" class="knot-dot" title="存在未解决心结" />
                </div>
                <div class="card-true-name">真名：{{ g.displayName }}</div>
              </div>
              <div class="card-badges">
                <span class="type-badge" :class="g.toneClass">{{ g.typeLabel }}</span>
                <span v-if="g.mentalBreak" class="status-badge mental">精神极限</span>
              </div>
            </div>
            <div class="card-stats-row">
              <ManaSigil
                compact
                :percent="g.magicPercent"
                :current="g.magicCurrent"
                :max="g.magicMax"
                :stage="g.manaStageClass"
                :fallen="g.fallen"
              />
              <span class="attitude-badge compact" :class="g.attitudeToneClass">{{ g.attitude }}</span>
            </div>
            <div class="card-foot">
              <span class="detail-link">查看详情</span>
            </div>
          </button>
        </div>

        <div v-else class="empty">魔法少女为空</div>
      </div>
    </Transition>

    <!-- 🆕 Knot edit dialog -->
    <Transition name="fade">
      <div v-if="knotDialogOpen" key="knot-dialog" class="dialog-mask" @click.self="closeKnotDialog">
        <div class="dialog">
          <div class="dialog-head">
            <div>
              <div class="dialog-title">{{ knotDialogMode === 'add' ? '新增心结' : '编辑心结' }}</div>
              <div class="dialog-subtitle">
                {{ knotDialogMode === 'add' ? '添加一个未解决的心结条目' : '修改心结的名称或描述' }}
              </div>
            </div>
          </div>
          <div class="dialog-body">
            <label class="field">
              <span class="field-label">心结名称</span>
              <input v-model="knotName" class="input" type="text" placeholder="例如：对姐姐的愧疚" />
            </label>
            <label class="field" style="margin-top: 12px">
              <span class="field-label">描述</span>
              <textarea v-model="knotDesc" class="textarea" rows="3" placeholder="心结的具体描述…" />
            </label>
          </div>
          <div class="dialog-actions">
            <button class="btn primary" type="button" :disabled="!knotName.trim()" @click="confirmKnot">保存</button>
            <button class="btn" type="button" @click="closeKnotDialog">取消</button>
          </div>
        </div>
      </div>
    </Transition>

    <!-- Fall dialog -->
    <Transition name="fade">
      <div v-if="fallDialogOpen" key="fall-dialog" class="dialog-mask" @click.self="closeFallDialog">
        <div class="dialog">
          <div class="dialog-head">
            <div>
              <div class="dialog-title">反转</div>
              <div class="dialog-subtitle">
                {{ fallTargetGirl?.magicName || '该角色' }} 将反转为 {{ fallToFallen ? '堕落魔法少女' : '魔法少女' }}
              </div>
            </div>
          </div>
          <div class="dialog-body">
            <label class="field">
              <span class="field-label">反转魔法名</span>
              <input
                v-model="fallNewMagicName"
                class="input"
                type="text"
                :readonly="fallTargetGirl?.protected"
                :placeholder="fallTargetGirl?.protected ? '世界书内置角色，魔法名自动选择' : '输入反转后的魔法名'"
              />
            </label>
            <div v-if="fallTargetGirl?.protected" class="hint">
              世界书内置角色的魔法名根据堕落/常态状态自动切换，无需手动填写。
            </div>
            <div v-else class="hint">动态角色只存当前态的魔法名，所以反转时需要同时填写新的当前魔法名。</div>
          </div>
          <div class="dialog-actions">
            <button class="btn primary" type="button" :disabled="!fallNewMagicName.trim()" @click="confirmFall">
              确认切换
            </button>
            <button class="btn" type="button" @click="closeFallDialog">取消</button>
          </div>
        </div>
      </div>
    </Transition>

    <!-- Delete dialog -->
    <Transition name="fade">
      <div v-if="deleteDialogOpen" key="delete-dialog" class="dialog-mask" @click.self="closeDeleteDialog">
        <div class="dialog compact">
          <div class="dialog-head">
            <div>
              <div class="dialog-title">删除魔法少女</div>
              <div class="dialog-subtitle">{{ deleteTargetGirl?.magicName }} 将从当前记录中移除。</div>
            </div>
          </div>
          <div class="dialog-body">
            <div class="delete-copy">删除后将移除该魔法少女在变量中的存储。</div>
          </div>
          <div class="dialog-actions">
            <button class="btn danger" type="button" @click="confirmDelete">确认删除</button>
            <button class="btn" type="button" @click="closeDeleteDialog">取消</button>
          </div>
        </div>
      </div>
    </Transition>
  </section>
</template>

<style scoped>
.section,
.list-view,
.detail-view {
  display: flex;
  flex-direction: column;
  gap: 12px;
}
.list-view {
  max-height: var(--list-max-height);
  overflow-y: auto;
  padding-right: 4px;
