<script setup lang="ts">
import { computed, inject, ref, watch } from 'vue';
import ViewModeToggle from '../components/ViewModeToggle.vue';
import { useDataStore } from '../store';

const store = useDataStore();

const EMOTION_WEIGHTS: Record<string, number> = { 极端: 4, 强烈: 3, 普通: 2, 些许: 1, 微弱: 0 };

function emotionTone(level: string): string {
  switch (level) {
    case '微弱':
    default:
      return 'tag-faint';
    case '些许':
      return 'tag-light';
    case '普通':
      return 'tag-normal';
    case '强烈':
      return 'tag-strong';
    case '极端':
      return 'tag-extreme';
  }
}

interface Character {
  key: string;
  displayName: string;
  transformed: boolean;
  thought: string;
  emotions: { name: string; level: string; toneClass: string; weight: number }[];
  isMagicalGirl: boolean;
  magicalGirlKey: string | null;
}

const expanded = ref(new Set<string>());
const viewMode = ref('compact');

const injectSwitchToTab = inject<(tab: string, opts?: { selectGirl: string }) => void>('switchToTab', () => {});

const characters = computed<Character[]>(() => {
  const girls = ((store.data as Record<string, unknown>).魔法少女 as Record<string, Record<string, unknown>>) ?? {};
  const present = ((store.data as Record<string, unknown>).在场角色 as Record<string, Record<string, unknown>>) ?? {};

  return Object.entries(present)
    .map(([key, char]) => {
      const displayName = ((char.名称 as string) || key).trim() || key;

      const resolved = resolveMagicalGirl(displayName, girls);
      const emotions = Object.entries((char.感情 as Record<string, string>) ?? {})
        .map(([name, level]) => ({
          name,
          level,
          toneClass: emotionTone(level),
          weight: EMOTION_WEIGHTS[level] ?? -1,
        }))
        .sort((a, b) => b.weight - a.weight || a.name.localeCompare(b.name, 'zh-Hans-CN'));

      return {
        key,
        displayName,
        transformed: char.是否变身 === true,
        thought: (char.心声 as string) || '……',
        emotions,
        isMagicalGirl: resolved !== null,
        magicalGirlKey: resolved,
      };
    })
    .sort((a, b) => a.displayName.localeCompare(b.displayName, 'zh-Hans-CN'));
});

function resolveMagicalGirl(name: string, girls: Record<string, Record<string, unknown>>): string | null {
  if (!name) return null;
  const n = name.trim();
  if (girls[n]) return n;
  for (const [key, g] of Object.entries(girls)) {
    if ((g.真名 as string)?.trim() === n || (g.魔法名 as string)?.trim() === n) return key;
  }
  return null;
}

function toggleExpand(key: string) {
  if (expanded.value.has(key)) expanded.value.delete(key);
  else expanded.value.add(key);
}

function jumpToGirl(key: string) {
  injectSwitchToTab('girls', { selectGirl: key });
}

watch(
  () => characters.value.map(c => c.key),
  keys => {
    const set = new Set(keys);
    expanded.value.forEach(k => {
      if (!set.has(k)) expanded.value.delete(k);
    });
  },
);
</script>

<template>
  <section class="section">
    <!-- Toolbar -->
    <div v-if="characters.length" class="toolbar">
      <div class="count">{{ characters.length }} 名角色在场</div>
      <ViewModeToggle :item-count="characters.length" storage-key="present" @change="v => (viewMode = v)" />
    </div>

    <!-- Compact -->
    <div v-if="characters.length && viewMode === 'compact'" class="compact-list">
      <article
        v-for="c in characters"
        :key="c.key"
        class="compact-item"
        :class="{ 'is-magical-girl': c.isMagicalGirl, expanded: expanded.has(c.key) }"
      >
        <div class="compact-main" @click="toggleExpand(c.key)">
          <div class="compact-left">
            <div class="compact-name">
              {{ c.displayName }}
              <span v-if="c.isMagicalGirl" class="mg-badge" title="魔法少女">✦</span>
            </div>
            <span class="compact-status" :class="c.transformed ? 'transformed' : 'normal'">
              {{ c.transformed ? '变身' : '常态' }}
            </span>
          </div>
          <div class="compact-right">
            <div class="emotions-mini">
              <span v-for="e in c.emotions" :key="e.name" class="emotion-chip" :class="e.toneClass">{{ e.name }}</span>
              <span v-if="!c.emotions.length" class="emotion-chip tag-faint">暂无</span>
            </div>
            <button class="expand-btn" type="button" :aria-label="expanded.has(c.key) ? '收起' : '展开'">
              <svg viewBox="0 0 24 24" :class="{ rotated: expanded.has(c.key) }">
                <path d="M6 9l6 6 6-6" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" />
              </svg>
            </button>
          </div>
        </div>
        <Transition name="expand">
          <div v-if="expanded.has(c.key)" class="compact-detail">
            <div class="detail-row">
              <span class="detail-label">心声</span><span class="detail-value">{{ c.thought }}</span>
            </div>
            <div class="detail-row">
              <span class="detail-label">感情</span>
              <div class="emotion-tags">
                <span v-for="e in c.emotions" :key="e.name" class="emotion-tag" :class="e.toneClass">
                  <strong>{{ e.name }}</strong
                  ><span>{{ e.level }}</span>
                </span>
                <span v-if="!c.emotions.length" class="no-emotion">暂无</span>
              </div>
            </div>
            <div v-if="c.isMagicalGirl && c.magicalGirlKey" class="detail-row">
