              <button class="jump-btn" type="button" @click="jumpToGirl(c.magicalGirlKey || '')">查看详情 →</button>
            </div>
          </div>
        </Transition>
      </article>
    </div>

    <!-- Detail -->
    <div v-else-if="characters.length && viewMode === 'detail'" class="detail-list">
      <article v-for="c in characters" :key="c.key" class="detail-item" :class="{ 'is-magical-girl': c.isMagicalGirl }">
        <div class="top-row">
