              <span v-if="c.isMagicalGirl" class="mg-badge" title="魔法少女">✦ 魔法少女</span>
            </div>
          </div>
          <div class="badges">
            <span class="badge" :class="c.transformed ? 'badge-accent' : 'badge-muted'">
              {{ c.transformed ? '已变身' : '未变身' }}
            </span>
          </div>
        </div>
        <div class="thought-box">
          <div class="label">心声</div>
          <div class="thought">{{ c.thought }}</div>
        </div>
        <div class="tags">
          <span v-for="e in c.emotions" :key="e.name" class="tag" :class="e.toneClass">
