<script setup lang="ts">
import { ref, watchEffect } from 'vue';

const PREF_KEY = 'msp_v4:theme';

function getStored(): string {
  try {
    return localStorage.getItem(PREF_KEY) || 'dark';
  } catch {
    return 'dark';
  }
}
function setStored(v: string) {
  try {
    localStorage.setItem(PREF_KEY, v);
  } catch {
    /* noop */
  }
}

function applyTheme(theme: string) {
  document.documentElement.setAttribute('data-theme', theme);
}

const isDark = ref(getStored() === 'dark');

// Apply on load
applyTheme(isDark.value ? 'dark' : 'light');

function toggle() {
  isDark.value = !isDark.value;
  setStored(isDark.value ? 'dark' : 'light');
}

watchEffect(() => {
  applyTheme(isDark.value ? 'dark' : 'light');
});
</script>

<template>
  <button
    class="theme-toggle"
    type="button"
    :title="isDark ? '切换到日间模式' : '切换到夜间模式'"
    :aria-label="isDark ? '切换到日间模式' : '切换到夜间模式'"
    @click="toggle"
  >
    <Transition name="theme-icon" mode="out-in">
      <svg v-if="isDark" key="moon" class="icon" viewBox="0 0 24 24" aria-hidden="true">
        <path
          d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"
          fill="currentColor"
          stroke="currentColor"
          stroke-width="1.5"
          stroke-linecap="round"
          stroke-linejoin="round"
        />
      </svg>
      <svg v-else key="sun" class="icon" viewBox="0 0 24 24" aria-hidden="true">
        <circle cx="12" cy="12" r="4" fill="currentColor" />
        <path
          d="M12 2v2M12 20v2M4.93 4.93l1.41 1.41M17.66 17.66l1.41 1.41M2 12h2M20 12h2M6.34 17.66l-1.41 1.41M19.07 4.93l-1.41 1.41"
          stroke="currentColor"
          stroke-width="2"
          stroke-linecap="round"
        />
      </svg>
    </Transition>
  </button>
</template>

